#include <stdio.h>
#include <string.h>
int main() {
    int n;
    scanf("%d", &n);
    char s[n + 1];
    scanf("%s", s);
    int open = 0, close = 0;
    for (int i = 0; i < n; i++) {
        if (s[i] == '(') open++;
        else close++;
    }
    printf("%d\n", (open > close) ? open - close : close - open);
    return 0;
}

