code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        String s = scanner.next();
        int open = 0, close = 0;
        for (int i = 0; i < n; i++) {
            if (s.charAt(i) == '(') open++;
            else close++;
        }
        System.out.println((open > close) ? open - close : close - open);
    }
}

code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let n;
let s;
readline.on('line', line => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        s = line;
        let open = 0;
        let close = 0;
        for (let j = 0; j < n; j++) {
            if (s[j] === '(') open++;
            else close++;
        }
        console.log(Math.abs(open - close));
        readline.close();
    }
    i++;
});
